const lead = $('Leila Webhook Ingestion').item.json.body;
const analysis = $('Gemini/OpenAI Lead Parser').item.json.choices[0].message.content;
const data = typeof analysis === 'string' ? JSON.parse(analysis) : analysis;

// Calculate CRM Lead Priority Score
let priorityScore = 50; // Base score
if (data.intent === 'buy_resale' || data.intent === 'invest') priorityScore += 20;
if (data.budget_egp > 15000000) priorityScore += 15; // Luxury Segment
if (data.timeline_months <= 2) priorityScore += 15;   // High Urgency

let priority = 'Low';
if (priorityScore >= 80) priority = 'High';
else if (priorityScore >= 65) priority = 'Medium';

return {
  json: {
    client_name: lead.client_name,
    client_phone: lead.client_phone,
    raw_intent: data.intent,
    budget: data.budget_egp,
    timeline: data.timeline_months,
    summary: data.client_summary,
    score: priorityScore,
    priority: priority,
    assigned_agent: lead.assigned_agent_id || "agent_unassigned"
  }
};

